@app.route('/static/<path:filename>')
def serve_static(filename: str):
    file_path = (BASE_DIR / filename).resolve()
    if not str(file_path).startswith(str(BASE_DIR) + '/'):
        abort(403)
    return Response(file_path.read_bytes(), mimetype='application/octet-stream')

from django.template import loader
from django.http import HttpResponse
import re

ALLOWED_TEMPLATE_RE = re.compile(r'^[a-zA-Z0-9_\-/]+\.html$')

def render_custom_template(request):
    template_name = request.GET.get('template', 'default.html')
    if not ALLOWED_TEMPLATE_RE.match(template_name):
        template_name = 'default.html'
    template = loader.get_template(template_name)
    return HttpResponse(template.render({}, request))

