from flask import request, jsonify, abort
import os

TEMP_DIR = os.path.realpath('/tmp/user_uploads')

@app.route('/api/delete-temp-file', methods=['DELETE'])
def delete_temp_file():
    filename = request.json.get('filename', '')
    filepath = os.path.realpath(os.path.join(TEMP_DIR, filename))
    if not filepath.startswith(TEMP_DIR + os.sep):
        abort(403)
    if os.path.exists(filepath):
        os.remove(filepath)
        return jsonify({'deleted': os.path.basename(filepath)})
    return jsonify({'error': 'not found'}), 404

