import os
from django.http import FileResponse

REPORTS_DIR = os.path.realpath('/var/app/reports')

def serve_user_report(request, report_id: int):
    report = get_object_or_404(Report, pk=report_id, owner=request.user)
    # Validate the stored path against the allowed directory at access time
    file_path = os.path.realpath(report.file_path)
    if not file_path.startswith(REPORTS_DIR + os.sep):
        raise PermissionDenied('Invalid report path')
    return FileResponse(open(file_path, 'rb'))

import os
import re

SAFE_NAME_RE = re.compile(r'^[a-zA-Z0-9_\-]+$')  # no slashes, no dots

def load_config(config_name: str) -> dict:
    if not SAFE_NAME_RE.match(config_name):
        raise ValueError(f'Invalid config name: {config_name!r}')
    config_dir = os.path.realpath(os.path.join(os.path.dirname(__file__), 'configs'))
    config_path = os.path.realpath(os.path.join(config_dir, config_name + '.json'))
    if not config_path.startswith(config_dir + os.sep):
        raise ValueError('Config path outside allowed directory')
    with open(config_path) as f:
        import json
        return json.load(f)
